#!/usr/bin/env node
// Generates src/DocsContent.generated.js: a { "<relative/path.md>": "<raw markdown>" }
// map of every doc under public-dev/docs.
//
// Why: on web the docs are fetched over HTTP from the server that serves public-dev/docs.
// A native (Android/iOS) app has no such server, so the markdown must be bundled. Rather
// than treat .md as fetchable assets (file:// fetch is unreliable in release APKs), we inline
// the content as strings and render it via MarkdownViewer.Code on native. See DocsContent.fs
// and RenderHelpers.docMarkdownSource. Re-run whenever docs change:
//   node scripts/gen-docs-bundle.js
const fs = require("fs");
const path = require("path");

const docsDir = path.resolve(__dirname, "..", "public-dev", "docs");
const outFile = path.resolve(__dirname, "..", "src", "DocsContent.generated.js");

function walk(dir) {
  let out = [];
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    const full = path.join(dir, entry.name);
    if (entry.isDirectory()) out = out.concat(walk(full));
    else if (entry.isFile() && entry.name.endsWith(".md")) out.push(full);
  }
  return out;
}

const files = walk(docsDir).sort();
const bundle = {};
for (const full of files) {
  // Key = path relative to public-dev/docs, posix separators (matches the "/docs/" + url
  // form the routes build, minus the leading "/docs/").
  const key = path.relative(docsDir, full).split(path.sep).join("/");
  bundle[key] = fs.readFileSync(full, "utf8");
}

const header =
  "// AUTOGENERATED by scripts/gen-docs-bundle.js -- DO NOT EDIT.\n" +
  "// " + files.length + " docs bundled for native (web fetches them over HTTP instead).\n";
fs.writeFileSync(outFile, header + "module.exports = " + JSON.stringify(bundle) + ";\n");
console.log("Wrote " + outFile + " (" + files.length + " docs, " +
  (fs.statSync(outFile).size / 1024).toFixed(0) + " KB)");
